export const ARTICLES = RAW.map(a => ({
  ...a,
  readTime: readTime(a.content),
  isPublished: new Date(a.publishDate) <= new Date(),
}));

export const PUBLISHED = ARTICLES.filter(a => a.isPublished);

export const CATEGORIES = ['All', 'Company News', 'Capabilities', 'Markets', 'Industry', 'Automata Aviation'];

export function getArticle(slug) {
  return ARTICLES.find(a => a.slug === slug) || null;
}

export function getRelated(article, count = 3) {
  return PUBLISHED
    .filter(a => a.id !== article.id && a.category === article.category)
    .slice(0, count)
    .concat(
      PUBLISHED.filter(a => a.id !== article.id && a.category !== article.category)
    )
    .slice(0, count);
}

export function getNextPublish() {
  const next = ARTICLES.find(a => !a.isPublished);
  if (!next) return null;
  const d = new Date(next.publishDate);
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const diff = Math.ceil((d - today) / (1000 * 60 * 60 * 24));
  return diff;
}
